import{_ as r,a as e}from"./chunks/Props_header.lzh95bVN.js";import{_ as o}from"./chunks/Props_details.D3Psvyd2.js";import{_ as t,c as s,o as l,ag as n}from"./chunks/framework.DVUBUV_u.js";const b=JSON.parse('{"title":"Общие принципы интерфейса","description":"","frontmatter":{"title":"Общие принципы интерфейса"},"headers":[],"relativePath":"ru/general_principles.md","filePath":"ru/general_principles.md"}'),i={name:"ru/general_principles.md"};function p(h,a,d,c,u,m){return l(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="общие-принципы-интерфеиса" tabindex="-1">Общие принципы интерфейса <a class="header-anchor" href="#общие-принципы-интерфеиса" aria-label="Permalink to &quot;Общие принципы интерфейса&quot;">​</a></h1><p>Общие сценарии работы с панелями Vue Inspector. О том, <strong>где</strong> отображается интерфейс (оверлей, вкладка DevTools, отдельное окно), см. <a href="/docs/ru/options/display_mode.html">Режимы отображения</a> и <a href="/docs/ru/install.html">Установка</a>.</p><p><img src="'+r+'" alt="Props, полноэкранный режим"></p><h2 id="навигация" tabindex="-1">Навигация <a class="header-anchor" href="#навигация" aria-label="Permalink to &quot;Навигация&quot;">​</a></h2><p>Интерфейс приложения построен вокруг двух рабочих вкладок: основной области данных и дополнительной области детализации. В адаптивном режиме вкладки могут объединяться в один рабочий экран.</p><h2 id="управление-элементами" tabindex="-1">Управление элементами <a class="header-anchor" href="#управление-элементами" aria-label="Permalink to &quot;Управление элементами&quot;">​</a></h2><p>Во всех таблицах действия доступны двумя способами:</p><ul><li>через меню <strong>⋯</strong> в строке элемента;</li><li>через контекстное меню (<strong>ПКМ</strong>).</li></ul><p>Оба варианта равнозначны и используются во всех основных разделах приложения.</p><h2 id="верхняя-панель-управления" tabindex="-1">Верхняя панель управления <a class="header-anchor" href="#верхняя-панель-управления" aria-label="Permalink to &quot;Верхняя панель управления&quot;">​</a></h2><p>Большинство разделов используют общую верхнюю панель, которая включает поиск и дополнительные действия. Состав панели зависит от текущего режима работы и типа отображаемых данных.</p><p><img src="'+e+'" alt="Props, область заголовка"></p><h2 id="поиск" tabindex="-1">Поиск <a class="header-anchor" href="#поиск" aria-label="Permalink to &quot;Поиск&quot;">​</a></h2><p>Поиск является сквозным механизмом и поддерживается в основных разделах приложения.</p><p>Для поиска используется встроенный механизм среды выполнения:</p><ul><li><strong>Ctrl+F</strong> — поиск через встроенный поиск браузера или DevTools.</li></ul><p>Поведение поиска зависит от текущего <a href="/docs/ru/options/display_mode.html">режима отображения</a> и структуры данных конкретного раздела. Фильтры по разделам (запросы, props, store) описаны в соответствующих статьях — например, <a href="/docs/ru/network/general.html">Network — работа с запросами</a>.</p><h2 id="горячие-клавиши" tabindex="-1">Горячие клавиши <a class="header-anchor" href="#горячие-клавиши" aria-label="Permalink to &quot;Горячие клавиши&quot;">​</a></h2><p>Интерфейс поддерживает стандартные действия клавиатуры:</p><ul><li><strong>Ctrl+F</strong> — поиск по текущему разделу (см. выше);</li><li><strong>Esc</strong> — отмена текущего действия, например закрытие детализации или выход из режима <a href="/docs/ru/props/inspect.html">инспектора</a>.</li></ul><h2 id="работа-с-детализациеи" tabindex="-1">Работа с детализацией <a class="header-anchor" href="#работа-с-детализациеи" aria-label="Permalink to &quot;Работа с детализацией&quot;">​</a></h2><p>Многие сущности поддерживают режим детализации. Открытие выполняется через выбор элемента, а выход — клавишей <strong>Esc</strong> или возвратом к предыдущему состоянию интерфейса.</p><p><img src="'+o+'" alt="Детализация props"></p><h2 id="режимы-отображения" tabindex="-1">Режимы отображения <a class="header-anchor" href="#режимы-отображения" aria-label="Permalink to &quot;Режимы отображения&quot;">​</a></h2><p>В зависимости от способа запуска (<strong>Overlay</strong>, <strong>DevTools</strong>, <strong>Standalone</strong>) интерфейс может незначительно отличаться, сохраняя общую логику работы. Подробнее — <a href="/docs/ru/options/display_mode.html">Режимы отображения</a>, <a href="/docs/ru/extension.html">расширение браузера</a> и <a href="/docs/ru/standalone.html">отдельное приложение</a>.</p>',25)])])}const q=t(i,[["render",p]]);export{b as __pageData,q as default};
